+export type DurationHistoryEntry = DurationObservation | { observations: DurationObservation[] }
+export type DurationHistory = Record<string, DurationHistoryEntry>
+
+function observations(entry: DurationHistoryEntry | number | undefined): DurationObservation[] {
+  if (typeof entry === 'number') return [{ duration: entry, recordedAt: 0 }]
+  if (!entry) return []
+  return 'observations' in entry ? entry.observations : [entry]
+}
