+export async function readDurationHistory(path: string): Promise<DurationHistory | null> {
+  try {
+    const value = JSON.parse(await readFile(path, 'utf8'))
+    if (!value || typeof value !== 'object' || Array.isArray(value)) return null
+    return value as DurationHistory
+  }
+  catch {
+    return null
+  }
+}
+
+export function durationsFromHistory(history: DurationHistory, ttl: number, smoothing: DurationSmoothing, now = Date.now()): Map<string, number> {
+  const oldest = ttl > 0 ? now - ttl : -Infinity
+  return new Map(Object.entries(history).map(([path, entry]) => {
+    const valid = observations(entry).filter(item => item.recordedAt === 0 || item.recordedAt >= oldest)
+    return [path, smoothDuration(valid, smoothing)]
+  }))
+}
