+export function warnForShardImbalance(loads: number[], threshold: number, warn: (message: string) => void): void {
+  if (threshold === 0 || !loads.length) return
+  const max = Math.max(...loads)
+  const ratio = max === 0 ? 1 : Math.min(...loads) / max
